#!/bin/bash# Este script realiza uma análise metataxonômica da região 16S V3V4echo &#34;
Análise metataxonômica 16S regiões V3V4 Iniciada&#34;# Variáveis e parâmetrosAMOSTRA=&#34;16SV34&#34;usearch=&#34;usearch&#34; # Especificar caminho completo se necessárioprimer5=&#34;TCGTCGGCAGCGTCAGATGTGTATAAGAGACAGCCTACGGGNGGCWGCAG&#34; # Primer forwardprimer3=&#34;GTCTCGTGGGCTCGGAGATGTGTATAAGAGACAGGACTACHVGGGTATCTAATCC&#34; # Primer reverse# Unir paresecho &#34;
UNINDO OS PARES&#34;$usearch -fastq_mergepairs *1.fq -reverse *2.fq -fastq_maxdiffs 6 -fastqout ${AMOSTRA}_merged.fq -relabel @ 2&gt;&gt; ${AMOSTRA}_merged.log echo &#34;UNIÃO CONCLUÍDA&#34;# Remover primersecho &#34;
CUTADAPT&#34;# Cortando os primers e mantendo apenas as reads que foram cortadascutadapt -g &#34;$primer5&#34; ${AMOSTRA}_merged.fq --discard-untrimmed 2&gt;&gt;${AMOSTRA}_cut.log | cutadapt -a &#34;$primer3&#34; -o ${AMOSTRA}_merged_cut.fq --discard-untrimmed - 1&gt;&gt;${AMOSTRA}_cut.logecho &#34;CUTADAPT CONCLUÍDO&#34;# Descartar reads com errosecho &#34;
DESCARTANDO READS COM ERROS&#34;# Quality filtering: descartar reads que provavelmente possuem erros$usearch -fastq_filter ${AMOSTRA}_merged_cut.fq -fastq_maxee 1.0 -fastaout ${AMOSTRA}_filtered.fa -relabel Filt 2&gt;&gt;${AMOSTRA}_filter.logecho &#34;DESCARTE CONCLUÍDO&#34;# Encontrar sequências únicas e abundantesecho &#34;
ENCONTRAR ÚNICAS E ABUNDANTES&#34;$usearch -fastx_uniques ${AMOSTRA}_filtered.fa -fastaout ${AMOSTRA}_uniques.fa -sizeout -relabel Uniq 2&gt;&gt;${AMOSTRA}_uniques.log# Criar clusters de OTUs com 97% de similaridadeecho &#34;
CRIAR CLUSTERS DE OTUs COM 97% DE SIMILARIDADE&#34;$usearch -cluster_otus ${AMOSTRA}_uniques.fa -relabel ${AMOSTRA}_OTU -otus ${AMOSTRA}_otus.fa 2&gt;&gt;${AMOSTRA}_otus.log# Criar tabelas de OTUsecho &#34;
CRIAR TABELAS COM OS OTUs&#34;$usearch -otutab ${AMOSTRA}_merged.fq -otus ${AMOSTRA}_otus.fa -strand plus -otutabout ${AMOSTRA}_otutab.txt 2&gt;&gt;${AMOSTRA}_otutab.log# Criar e plotar a tabela de diversidade alfa (opcional)#echo &#34;
CRIAR E PLOTAR A TABELA DE DIVERSIDADE ALFA&#34;#Rscript /home/ufsb/bin/rare.R ${AMOSTRA}_otutab.txt# Mapear as OTUs contra banco de dadosecho &#34;
MAPEAR AS OTUs CONTRA BANCO DE DADOS&#34;mapseq -nthreads 8 ${AMOSTRA}_otus.fa &gt; ${AMOSTRA}_otus.mapseq 2&gt;&gt;${AMOSTRA}_otus.mapseq.log# Criar a tabela de OTUs para cada amostraecho &#34;
CRIAR A TABELA DE OTUs PARA CADA AMOSTRA&#34;for i in {2..13}do awk -F&#34;	&#34; &#39;{print $1,&#34;	&#34;,$&#39;&#34;$i&#34;&#39;}&#39; ${AMOSTRA}_otutab.txt | sed &#39;s/ //g&#39; &gt; &#34;C${i}G$(($i+1))_otutab.txt&#34;done# Unir as tabelas geradas pelo usearch e mapseq para abrir no Kronaecho &#34;
UNIR AS TABELAS GERADAS PELO USEARCH E MAPSEQ PARA ABRIR NO KRONA&#34;for i in {2..13}do concat_OTUs_Taxons.pl &#34;C${i}G$(($i+1))_otutab.txt&#34; ${AMOSTRA}_otus.mapseq &gt; &#34;C${i}G$(($i+1))_results.txt&#34;done# Criar um arquivo HTML para visualização dos resultadosecho &#34;
CRIAR UM ARQUIVO HTML PARA VISUALIZAÇÃO DOS RESULTADOS&#34;ktImportText C*_results.txt -o ${AMOSTRA}_results.htmlecho &#34;
ANÁLISE 16SV3V4 FINALIZADA&#34;&#34;
